"use client";

import React, {useState,useEffect} from "react";
import TourCard from "@/app/Components/tourcard";
import { db } from "@/lib/firebase";
import { collection, query, getDocs } from "firebase/firestore";

interface AttractionData {
  id: string;
  image: string;
  title: string;
  description: string;
  location: string;
  duration: string;
  price: string;
  activity: string;
  age: string;
}


 export default function Attractions () {

  const [attractions, setAttractions] = useState<AttractionData[]>([]);
       const [loading, setLoading] = useState<boolean>(true);

       useEffect(() => {
         const fetchAttractions = async () => {
           try {
             const q = query(collection(db, "attractions"));
             const querySnapshot = await getDocs(q);
              const attractionsData: AttractionData[] = [];
              querySnapshot.forEach((doc) => {
                const data = doc.data();
                attractionsData.push({
                  id: doc.id,
                  image: data.image || "",
                  title: data.title || "Untitled",
                  description: data.description || "No description available",
                  location: data.location || "Unknown",
                  duration: data.duration || "N/A",
                  price: data.price || "N/A",
                  activity: data.activity || "N/A",
                  age: data.age || "All ages",
                });
              });
              setAttractions(attractionsData);
              setLoading(false);
           } catch (error) {
             console.error("Error fetching attractions: ", error);
             setLoading(false);
           }
         };

         fetchAttractions();
       }, []);  

   
return(
    <>
      < section
        className=" relative h-96 bg-cover bg-center flex items-center "
        style={{backgroundImage:`url('/bg-image.jpeg')`}}>
            < div className="absolute inset-0 bg-gradient-to-b from-black/60 via-black/30 to-transparent" />
        <div className="relative z-10 text-center">
          <h1 className="text-4xl md:text-7xl text-left px-20 font-bold text-white drop-shadow-2xl">
            Attractions
          </h1>
          <div className="w-24 h-1 bg-orange-500 mx-auto mt-4 rounded-full" />
        </div>
      </section>


     
      <section className="py-16 bg-white">
        <div className="container mx-auto px-6">
          {loading ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
            {[1, 2, 3, 4, 5, 6].map((index) => (
              <div
                key={index}
                className="animate-pulse bg-gray-200 h-80 rounded-lg" />  
            ))}
            
          </div>
          ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
            {attractions.map((attraction) => (
              <TourCard
                key={attraction.id}
                image={attraction.image}
                title={attraction.title}
                description={attraction.description}
                location={attraction.location}
                duration={attraction.duration}
                price={attraction.price}
                activity={attraction.activity}
                age={attraction.age}
              />
            ))}
          </div>
          )}  
        </div>
      </section>
    </>
  );
}
